#define BLOCK_SIZE 16

double key_shift = 0.12345; 

// forward DFT (encryption/obfuscation)
void dft_transform(unsigned char* input, double complex* output, int n) {
  for (int k = 0; k < n; k++) {
    output[k] = 0;
    for (int t = 0; t < n; t++) {
